package com.hospital.management.controller.medical;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.MedicalRecordServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/medical-records/edit")public class MedicalRecordEditServlet extends HttpServlet {private final MedicalRecordService service;public MedicalRecordEditServlet(){this(new MedicalRecordServiceImpl());}public MedicalRecordEditServlet(MedicalRecordService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=MedicalRequest.id(q.getParameter("id"));MedicalRecord m=id==null?null:service.getRecord(id,MedicalRequest.user(q)).orElse(null);if(m==null){r.sendError(404);return;}show(q,r,form(m),m);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{MedicalRecordForm f=MedicalRequest.form(q);ServiceResult<Void>x=service.updateRecord(f,MedicalRequest.audit(q),MedicalRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/medical-records/view?id="+f.getMedicalRecordId()+"&message=updated");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());MedicalRecord m=f.getMedicalRecordId()==null?null:service.getRecord(f.getMedicalRecordId(),MedicalRequest.user(q)).orElse(null);show(q,r,f,m);}private void show(HttpServletRequest q,HttpServletResponse r,MedicalRecordForm f,MedicalRecord m)throws ServletException,IOException{if(m==null){r.sendError(404);return;}q.setAttribute("record",m);q.setAttribute("recordForm",f);q.setAttribute("formMode","EDIT");q.getRequestDispatcher("/WEB-INF/views/medical-records/form.jsp").forward(q,r);}private MedicalRecordForm form(MedicalRecord m){MedicalRecordForm f=new MedicalRecordForm();f.setMedicalRecordId(m.getMedicalRecordId());f.setAppointmentId(m.getAppointmentId());f.setSymptoms(m.getSymptoms());f.setDiagnosis(m.getDiagnosis());f.setTreatmentNotes(m.getTreatmentNotes());f.setAllergies(m.getAllergies());f.setBloodPressure(m.getBloodPressure());f.setTemperature(text(m.getTemperature()));f.setWeight(text(m.getWeight()));f.setHeight(text(m.getHeight()));return f;}private String text(Object v){return v==null?null:v.toString();}}
